class Shape:
    def area(self):
        pass

class Circle(Shape):
    def __init__(self, radius):
        self.radius = radius

class Square(Shape):
    def __init__(self, side):
        self.side = side

shapes = [Circle(5), Square(4)]
for shape in shapes:
    print(shape.area())

